import { useMemo, useState } from 'react';
import { useLocale } from '.';
import type { LocaleName } from '@universe-design/react-provider';
import { devWarning, warning } from '../../util';

type ImportLocaleFunc<T> = (locale: LocaleName) => Promise<T> | T;

export const useImportLocale = <T extends object>({
  importLocale,
  fallbackLocale,
}: {
  importLocale: ImportLocaleFunc<T>;
  fallbackLocale: T;
}) => {
  const { locale: localeName } = useLocale();
  const [locale, setLocale] = useState<T>();

  useMemo(() => {
    const maybeThenable = importLocale(localeName);
    if ('then' in maybeThenable) {
      maybeThenable
        .then(_locale => {
          setLocale(_locale);
        })
        .catch((err: Error) => {
          warning(
            false,
            devWarning(
              'importLocale',
              // eslint-disable-next-line max-len
              `${err.message}. Locale name \`${localeName}\` is not valid or something unexpected occurs. Your app will use \`en-US\` as a fallback.`,
            ),
          );
          setLocale(fallbackLocale);
        });
      return;
    }
    setLocale(maybeThenable);
  }, [fallbackLocale, importLocale, localeName]);

  return locale;
};
